Func<string, double> ParseTr = (txt) =>
{
    if (string.IsNullOrWhiteSpace(txt)) return 0.0;
    var s = txt.Trim().Replace(" ", "").Replace("'", "").Replace("\u00A0", "");
    int lastDot = s.LastIndexOf('.');
    int lastComma = s.LastIndexOf(',');
    if (lastDot >= 0 && lastComma >= 0)
    {
        if (lastComma > lastDot) s = s.Replace(".", "").Replace(",", \

);
        else s = s.Replace(",", "");
    }
    else if (lastComma >= 0)
    {
        s = s.Replace(",", \

);
    }
    double v = 0.0;
    try { v = Convert.ToDouble(s, System.Globalization.CultureInfo.InvariantCulture); } catch { }
    return v;
};

iDeal içinde bunun için en uygun yöntem Sistem.NesneKaydet ve Sistem.NesneGetir ile zaman damgası saklamaktır. Örnek:

var Now = DateTime.Now;
var windows = new [] {
    new { Saat = 10, Dakika = 30, Key = "Scan_10_30" },
    new { Saat = 14, Dakika = 30, Key = "Scan_14_30" }
};

bool active = false;
foreach (var w in windows)
{
    bool timeOk = (Now.Hour == w.Saat && Now.Minute >= w.Dakika && Now.Minute <= w.Dakika + 5);
    if (!timeOk) continue;

    var lastObj = Sistem.NesneGetir(w.Key);
    DateTime lastTime = lastObj == null ? DateTime.MinValue : (DateTime)lastObj;
    if (lastTime.Date == DateTime.Today) continue;

    Sistem.NesneKaydet(w.Key, Now);
    active = true;
    break;
}
if (!active) return null;

Aşağıdaki akış savunmacı bir alış iskeletidir:

string Anahtar = Sistem.Name + "," + Sembol;
double Pozisyon = 0, IslemFiyat = 0;
DateTime IslemTarih = DateTime.MinValue;
string Rezerv = "";
try { Pozisyon = Sistem.PozisyonKontrolOku(Anahtar, out IslemFiyat, out IslemTarih, out Rezerv); } catch { }

if (AlisSarti && Pozisyon <= 0)
{
    Sistem.EmirSembol = Sembol;
    Sistem.EmirIslem = "ALIS";
    Sistem.EmirTipi = "Piyasa";
    Sistem.EmirSuresi = "KIE";
    Sistem.EmirMiktari = Miktar;
    Sistem.EmirFiyati = SonFiyat;
    Sistem.EmirGonder();

    Sistem.PozisyonKontrolGuncelle(Anahtar, Miktar, SonFiyat, "ALIS");
}

